import 'package:dio/dio.dart';/// Base class for handling failuresabstract class Failure {  final String errMessage;  const Failure(this.errMessage);}/// Class to handle server-related failuresclass ServerFailure extends Failure {  ServerFailure(super.errMessage);  factory ServerFailure.unauthorized() {    return ServerFailure("Unauthorized access. Please login again.");  }  factory ServerFailure.fromDioError(DioException dioError) {    print('DioError: ${dioError.type}, Message: ${dioError.message}');    switch (dioError.type) {      case DioExceptionType.connectionTimeout:        return ServerFailure('Connection timeout with ApiServer');      case DioExceptionType.connectionError:        return ServerFailure('No Internet Connection');      case DioExceptionType.sendTimeout:        return ServerFailure('Send timeout with ApiServer');      case DioExceptionType.receiveTimeout:        return ServerFailure('Receive timeout with ApiServer');      case DioExceptionType.badResponse:        return dioError.response != null            ? ServerFailure.fromResponse(                dioError.response!.statusCode, dioError.response!.data)            : ServerFailure('Bad response from ApiServer');      case DioExceptionType.cancel:        return ServerFailure('Request to ApiServer was canceled');      case DioExceptionType.unknown:        return ServerFailure('Unexpected Error, Please try again!');      default:        return ServerFailure('Oops, there was an error. Please try again.');    }  }  factory ServerFailure.fromResponse(int? statusCode, dynamic response) {    print('45- Response statusCode: $statusCode, Response: $response');    if (response is Map<String, dynamic>) {      response.forEach((key, value) {      });      if (response.containsKey('error')) {        final error = response['error'];        if (error is Map<String, dynamic> && error.containsKey('message')) {          return ServerFailure(error['message']);        } else if (error is String) {          return ServerFailure(error);        }      }      if (response.containsKey('message')) {        return ServerFailure(response['message']);      }    } else if (response is String) {      return ServerFailure(response);    }    switch (statusCode) {      case 400:      case 401:      case 403:        return ServerFailure(            'Authentication error: ${response['error']['message'] ?? 'Unknown error'}');      case 404:        return ServerFailure('Your request not found. Please try later!');      case 500:        return ServerFailure('Internal Server error. Please try later.');      default:        return ServerFailure('Oops, there was an error. Please try again.');    }  }}